  1561→ *
  1562→ * const thingListeners = DisposableMap<Thing, IDisposable>();
  1563→ *
  1564→ * thingService.onDidAddThing(thing => {
  1565→ *   thingListeners.set(thing, anythingDataMultiplexer.add(thing.onData);
  1566→ * });
  1567→ * thingService.onDidRemoveThing(thing => {
  1568→ *   thingListeners.deleteAndDispose(thing);
  1569→ * });
  1570→ *
  1571→ * anythingDataMultiplexer.event(e => {
  1572→ *   console.log('Something fired data ' + e.data)
  1573→ * });
  1574→ * ```
