  1581→
  1582→	constructor() {
  1583→		this.emitter = new Emitter<T>({
  1584→			onWillAddFirstListener: () => this.onFirstListenerAdd(),
  1585→			onDidRemoveLastListener: () => this.onLastListenerRemove()
  1586→		});
  1587→	}
  1588→
  1589→	get event(): Event<T> {
  1590→		return this.emitter.event;
  1591→	}
  1592→
  1593→	add(event: Event<T>): IDisposable {
  1594→		const e = { event: event, listener: null };
  1595→		this.events.push(e);
  1596→
  1597→		if (this.hasListeners) {
  1598→			this.hook(e);
  1599→		}
  1600→
  1601→		const dispose = () => {
  1602→			if (this.hasListeners) {
  1603→				this.unhook(e);
  1604→			}
  1605→
  1606→			const idx = this.events.indexOf(e);
  1607→			this.events.splice(idx, 1);
  1608→		};
  1609→
  1610→		return toDisposable(createSingleCallFunction(dispose));
  1611→	}
  1612→
  1613→	private onFirstListenerAdd(): void {
  1614→		this.hasListeners = true;
  1615→		this.events.forEach(e => this.hook(e));
  1616→	}
  1617→
  1618→	private onLastListenerRemove(): void {
  1619→		this.hasListeners = false;
  1620→		this.events.forEach(e => this.unhook(e));
  1621→	}
