  1686→/**
  1687→ * The EventBufferer is useful in situations in which you want
  1688→ * to delay firing your events during some code.
  1689→ * You can wrap that code and be sure that the event will not
  1690→ * be fired during that wrap.
  1691→ *
  1692→ * ```
  1693→ * const emitter: Emitter;
  1694→ * const delayer = new EventDelayer();
  1695→ * const delayedEvent = delayer.wrapEvent(emitter.event);
  1696→ *
  1697→ * delayedEvent(console.log);
  1698→ *
  1699→ * delayer.bufferEvents(() => {
  1700→ *   emitter.fire(); // event will not be fired yet
  1701→ * });
  1702→ *
  1703→ * // event will only be fired at this point
  1704→ * ```
  1705→ */
  1706→export class EventBufferer {
  1707→
  1708→	private data: { buffers: Function[] }[] = [];
  1709→
  1710→	wrapEvent<T>(event: Event<T>): Event<T>;
  1711→	wrapEvent<T>(event: Event<T>, reduce: (last: T | undefined, event: T) => T): Event<T>;
  1712→	wrapEvent<T, O>(event: Event<T>, reduce: (last: O | undefined, event: T) => O, initial: O): Event<O>;
  1713→	wrapEvent<T, O>(event: Event<T>, reduce?: (last: T | O | undefined, event: T) => T | O, initial?: O): Event<O | T> {
  1714→		return (listener, thisArgs?, disposables?) => {
  1715→			return event(i => {
  1716→				const data = this.data[this.data.length - 1];
  1717→
  1718→				// Non-reduce scenario
  1719→				if (!reduce) {
  1720→					// Buffering case
  1721→					if (data) {
  1722→						data.buffers.push(() => listener.call(thisArgs, i));
  1723→					} else {
  1724→						// Not buffering case
  1725→						listener.call(thisArgs, i);
  1726→					}
  1727→					return;
  1728→				}
  1729→
  1730→				// Reduce scenario
  1731→				const reduceData = data as typeof data & {
  1732→					/**
  1733→					 * The accumulated items that will be reduced.
  1734→					 */
  1735→					items?: T[];
  1736→					/**
  1737→					 * The reduced result cached to be shared with other listeners.
  1738→					 */
  1739→					reducedResult?: T | O;
  1740→				};
  1741→
  1742→				// Not buffering case
  1743→				if (!reduceData) {
  1744→					// TODO: Is there a way to cache this reduce call for all listeners?
  1745→					listener.call(thisArgs, reduce(initial, i));
  1746→					return;
  1747→				}
  1748→
  1749→				// Buffering case
  1750→				reduceData.items ??= [];
  1751→				reduceData.items.push(i);
  1752→				if (reduceData.buffers.length === 0) {
  1753→					// Include a single buffered function that will reduce all events when we're done buffering events
  1754→					data.buffers.push(() => {
  1755→						// cache the reduced result so that the value can be shared across all listeners
  1756→						reduceData.reducedResult ??= initial
  1757→							? reduceData.items!.reduce(reduce as (last: O | undefined, event: T) => O, initial)
  1758→							: reduceData.items!.reduce(reduce as (last: T | undefined, event: T) => T);
  1759→						listener.call(thisArgs, reduceData.reducedResult);
  1760→					});
  1761→				}
  1762→			}, undefined, disposables);
  1763→		};
  1764→	}
  1765→
  1766→	bufferEvents<R = void>(fn: () => R): R {
  1767→		const data = { buffers: new Array<Function>() };
  1768→		this.data.push(data);
  1769→		const r = fn();
  1770→		this.data.pop();
  1771→		data.buffers.forEach(flush => flush());
  1772→		return r;
  1773→	}
  1774→}
